/**
 * Enhanced Service Worker for Offline Support
 * Extends the base Workbox service worker with custom caching strategies
 */

// Import Workbox libraries
importScripts('https://storage.googleapis.com/workbox-cdn/releases/7.0.0/workbox-sw.js');

const { precacheAndRoute, cleanupOutdatedCaches } = workbox.precaching;
const { registerRoute } = workbox.routing;
const { CacheFirst, NetworkFirst, StaleWhileRevalidate } = workbox.strategies;
const { ExpirationPlugin } = workbox.expiration;
const { CacheableResponsePlugin } = workbox.cacheableResponse;

// Precache static assets (generated by Next.js)
precacheAndRoute(self.__WB_MANIFEST || []);
cleanupOutdatedCaches();

// Cache name constants
const AUDIO_CACHE = 'bookbridge-audio-v1';
const API_CACHE = 'bookbridge-api-v1';
const IMAGE_CACHE = 'bookbridge-images-v1';

/**
 * Audio Files Caching Strategy
 * Cache audio files aggressively for offline playback
 */
registerRoute(
  ({ url }) => url.hostname.includes('supabase.co') && url.pathname.includes('/audio-files/'),
  new CacheFirst({
    cacheName: AUDIO_CACHE,
    plugins: [
      new CacheableResponsePlugin({
        statuses: [0, 200],
      }),
      new ExpirationPlugin({
        maxEntries: 200, // Store up to 200 audio files
        maxAgeSeconds: 30 * 24 * 60 * 60, // 30 days
        purgeOnQuotaError: true, // Auto-cleanup on quota error
      }),
    ],
  })
);

/**
 * API Caching Strategy
 * Cache API responses for offline access
 */
registerRoute(
  ({ url }) => url.pathname.startsWith('/api/') && url.pathname.includes('/bundles'),
  new NetworkFirst({
    cacheName: API_CACHE,
    plugins: [
      new CacheableResponsePlugin({
        statuses: [0, 200],
      }),
      new ExpirationPlugin({
        maxEntries: 50,
        maxAgeSeconds: 24 * 60 * 60, // 1 day
      }),
    ],
    networkTimeoutSeconds: 10, // Fall back to cache if network is slow
  })
);

/**
 * Image Caching Strategy
 */
registerRoute(
  ({ request }) => request.destination === 'image',
  new CacheFirst({
    cacheName: IMAGE_CACHE,
    plugins: [
      new CacheableResponsePlugin({
        statuses: [0, 200],
      }),
      new ExpirationPlugin({
        maxEntries: 100,
        maxAgeSeconds: 30 * 24 * 60 * 60, // 30 days
      }),
    ],
  })
);

/**
 * Offline Fallback
 * Serve offline page when network is unavailable
 */
const OFFLINE_PAGE = '/offline.html';

// Cache offline page during install
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open('offline-v1').then((cache) => {
      return cache.addAll([OFFLINE_PAGE]);
    })
  );
  self.skipWaiting();
});

// Serve offline page as fallback
self.addEventListener('fetch', (event) => {
  if (event.request.mode === 'navigate') {
    event.respondWith(
      fetch(event.request).catch(() => {
        return caches.match(OFFLINE_PAGE);
      })
    );
  }
});

/**
 * Background Sync for Download Queue
 * Resume interrupted downloads when connection is restored
 */
self.addEventListener('sync', (event) => {
  if (event.tag === 'sync-downloads') {
    event.waitUntil(syncDownloads());
  }
});

async function syncDownloads() {
  console.log('📡 Syncing interrupted downloads...');

  // Notify all clients to resume downloads
  const clients = await self.clients.matchAll();
  clients.forEach((client) => {
    client.postMessage({
      type: 'SYNC_DOWNLOADS',
      timestamp: Date.now(),
    });
  });
}

/**
 * Handle messages from clients
 */
self.addEventListener('message', (event) => {
  if (event.data && event.data.type === 'SKIP_WAITING') {
    self.skipWaiting();
  }

  if (event.data && event.data.type === 'CACHE_AUDIO') {
    // Pre-cache audio URLs
    event.waitUntil(
      caches.open(AUDIO_CACHE).then((cache) => {
        return cache.addAll(event.data.urls || []);
      })
    );
  }

  if (event.data && event.data.type === 'CLEAR_CACHE') {
    // Clear specific cache
    event.waitUntil(
      caches.delete(event.data.cacheName || AUDIO_CACHE)
    );
  }
});

/**
 * Quota Management
 * Monitor and handle storage quota
 */
self.addEventListener('quotaexceeded', (event) => {
  console.warn('⚠️ Storage quota exceeded');

  // Notify clients about quota issues
  self.clients.matchAll().then((clients) => {
    clients.forEach((client) => {
      client.postMessage({
        type: 'QUOTA_EXCEEDED',
        timestamp: Date.now(),
      });
    });
  });
});

/**
 * Activation - Clean up old caches
 */
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          // Delete old version caches
          if (cacheName.startsWith('bookbridge-') && !cacheName.includes('-v1')) {
            console.log('🧹 Deleting old cache:', cacheName);
            return caches.delete(cacheName);
          }
        })
      );
    })
  );

  self.clients.claim();
});

console.log('✅ BookBridge Enhanced Service Worker loaded');
